const Qualifier = require('../../../../../src/lib/annotations/inject/Qualifier');
const { expect } = require('chai');

describe('Qualifier Annotation', () => {
  it('should store the correct name from args', () => {
    const qualifier = new Qualifier(['MyService']);
    expect(qualifier.name).to.equal('MyService');
  });

  it('should default to null if no name is provided', () => {
    const qualifier = new Qualifier();
    expect(qualifier.name).to.be.null;
  });
});
